descriptions = {
    638: ('Palantir Technologies Inc', 'US AI and data analytics platform. Exceptional ROIC.', 'AI analytics platform leader.', "Palantir provides AI-powered data analytics platforms for government and commercial clients. The company Gotham platform serves defence and intelligence agencies while Foundry and AIP serve commercial enterprises — a dominant position in mission-critical AI analytics.", 'AI analytics platform. Exceptional ROIC.', 'Government AI platform compounder.', "A US AI analytics platform with a 296.7% ROIC and EPS growth of 20.9% annualised. Palantir dominates mission-critical AI analytics for US government and defence — transitioning to commercial enterprise with AIP driving rapid growth in the private sector.", ["AI-powered analytics platforms for US government, defence and commercial enterprises.", "ROIC of 296.7% — extraordinary returns from dominant government AI analytics position.", "EPS grew 20.9% annualised as commercial AIP platform adoption accelerated strongly.", "Revenue grew 56.2% annualised as AI platform demand from government and enterprise surged."]),
    639: ('Privia Health Group Inc', 'US physician enablement platform. High growth.', 'Physician platform growth.', "Privia Health is a US technology-driven physician enablement company helping independent doctors transition to value-based care. The company provides practice management, technology, and administrative support to physician groups across the US.", 'Physician platform. High growth.', 'Healthcare platform compounder.', "A US physician enablement company with EPS growth improving as the value-based care platform scales. Privia Health helps independent physicians manage practices efficiently — a growing market as US healthcare shifts toward value-based reimbursement models.", ["Technology and administrative support for independent physician practices.", "Revenue grew 22.3% annualised as physician group adoption of the platform expanded.", "Growing market as US healthcare system transitions toward value-based care models.", "Platform economics improve as physician network scale drives operating leverage."]),
    640: ('Proto Labs Inc', 'US digital manufacturing platform. Growth recovery.', 'Digital manufacturing recovery.', "Proto Labs is a US digital manufacturing company providing custom parts through CNC machining, injection moulding, and 3D printing. The company serves engineers and product developers needing rapid prototype and low-volume production parts.", 'Digital manufacturing. Growth recovery.', 'Custom parts platform recovery.', "A US digital manufacturing platform with a 3.7% ROIC recovering as prototype and custom parts demand normalises. Proto Labs provides rapid CNC, moulding, and 3D printing — improving financial metrics as engineering and product development activity recovers.", ["Custom parts through CNC machining, injection moulding and 3D printing.", "Recovery play as prototype and custom manufacturing demand normalises.", "Revenue grew 6.4% annualised as engineering and product development activity expanded.", "Digital platform model with improving unit economics from manufacturing scale."]),
    641: ('Pursuit Attractions & Hospitality', 'US tourism and attractions. High revenue growth.', 'Experiential tourism growth.', "Pursuit is a US company operating visitor attractions, hospitality, and adventure experiences at iconic natural destinations — including Glacier National Park, Banff, and Reykjavik. The company benefits from structural growth in experiential travel and nature-based tourism.", 'Experiential tourism. High revenue growth.', 'Nature tourism compounder.', "A US experiential tourism company with revenue growth of 23.4% annualised operating attractions at Glacier, Banff, and Reykjavik. Pursuit benefits from structural growth in experiential travel — visitors seeking authentic nature experiences at iconic destinations.", ["Visitor attractions and hospitality at Glacier, Banff and Reykjavik.", "Revenue grew 23.4% annualised as experiential and nature-based tourism expanded.", "EPS grew 15.4% annualised with improving attraction utilisation and pricing.", "Structural growth in experiential travel driving consistent visitor volume increases."]),
    642: ('Qorvo Inc', 'US radio frequency semiconductors. Growth recovery.', 'RF semiconductor recovery.', "Qorvo designs and manufactures radio frequency semiconductors for smartphones, defence, and infrastructure applications. The company is recovering as smartphone RF content and defence electronics demand normalise following inventory correction.", 'RF semiconductors. Growth recovery.', 'RF chip recovery play.', "A US RF semiconductor company with an 8.2% ROIC recovering as smartphone and defence demand normalises. Qorvo RF chips enable wireless connectivity in smartphones and defence systems — improving financial metrics as the semiconductor inventory cycle turns.", ["Radio frequency semiconductors for smartphones, defence and wireless infrastructure.", "ROIC of 8.2% recovering as smartphone RF demand and defence electronics normalise.", "Inventory correction cycle turning with improving demand from OEM customers.", "Structural demand from 5G network expansion and defence RF system upgrades."]),
    643: ('QuinStreet Inc', 'US performance marketing platform. High ROIC.', 'Performance marketing compounder.', "QuinStreet is a US performance marketing company operating vertical media platforms for insurance, financial services, and home services. The company connects consumers seeking quotes with service providers — earning performance fees only when leads convert.", 'Performance marketing. High ROIC growth.', 'Digital marketing compounder.', "A US performance marketing platform with a 29.9% ROIC and EPS growth of 19.9% annualised. QuinStreet operates vertical media for insurance and financial services — a capital-light model earning performance fees from qualified lead delivery.", ["Performance marketing platforms for insurance, financial services and home services.", "ROIC of 29.9% reflects strong returns from a capital-light performance fee model.", "EPS grew 19.9% annualised as vertical media traffic and conversion rates improved.", "Revenue grew 19.0% annualised with consistent growth in high-intent consumer traffic."]),
    644: ('RingCentral Inc', 'US cloud communications platform. High ROIC.', 'Cloud UCaaS platform leader.', "RingCentral is a US cloud-based unified communications company providing business phone, video meetings, and messaging. The company is the leading independent UCaaS platform — serving enterprises transitioning from on-premise phone systems to cloud communications.", 'Cloud communications. High ROIC growth.', 'UCaaS platform compounder.', "A US cloud communications platform with a 33.3% ROIC and EPS growth of 20.2% annualised. RingCentral is the leading independent UCaaS provider serving enterprise communications — high switching costs from deep IT integration create durable recurring subscription revenue.", ["Cloud business phone, video and messaging for enterprise communications.", "ROIC of 33.3% reflects strong subscription economics from enterprise UCaaS platform.", "EPS grew 20.2% annualised as enterprise cloud communications adoption accelerated.", "Revenue grew 4.8% annualised with consistent enterprise subscription additions and expansion."]),
    645: ('Saga Furs', 'Finnish fur auction platform. High ROIC.', 'Fur auction market leader.', "Saga Furs is a Finnish fur auction company operating the largest fur auction platform globally. The company connects fur farmers with international buyers — a niche marketplace with strong brand recognition in premium fur markets.", 'Fur auction platform. High ROIC.', 'Specialty auction compounder.', "A Finnish fur auction company with a 13.6% ROIC operating the global fur auction market. Saga Furs connects premium fur farmers with international buyers — a niche marketplace with strong barriers to entry from established buyer and seller relationships.", ["Global fur auction platform connecting fur farmers with international premium buyers.", "ROIC of 13.6% reflects consistent returns from a dominant niche auction marketplace.", "EPS grew 19.4% annualised as fur market volumes and pricing recovered.", "Strong barriers to entry from established international buyer and seller relationships."]),
    646: ('Seneca Foods Corp', 'US canned vegetables. CANSLIM growth screen.', 'Canned food growth play.', "Seneca Foods is the largest private-label canned vegetable producer in the US. The company screens on CANSLIM criteria — consistent earnings, defensive food demand, and improving technical momentum from a value-priced consumer staples business.", 'Canned vegetables. CANSLIM growth.', 'Defensive food growth compounder.', "A US canned fruit and vegetable producer with a 9.0% ROIC screening on CANSLIM criteria. Seneca Foods is the largest US private-label canned vegetable producer — recession-resistant business with consistent demand and improving earnings momentum.", ["Canned and frozen fruits and vegetables under Seneca, Libby and private-label brands.", "Largest private-label canned vegetable producer in the US — scale creates cost advantages.", "ROIC of 9.0% reflects consistent returns from a recession-resistant defensive food business.", "Revenue growing 4.6% annualised with consistent demand from retail and foodservice channels."]),
    647: ('SharkNinja Inc', 'US consumer appliances. High growth.', 'Consumer appliance growth leader.', "SharkNinja designs and markets Shark vacuums and Ninja kitchen appliances globally. The company has a strong track record of innovation and category expansion — launching successful new products in air fryers, food processors, and outdoor grills.", 'Consumer appliances. High growth momentum.', 'Appliance brand compounder.', "A US consumer appliance company with a 25.1% ROIC and EPS growth of 16.1% annualised. SharkNinja Shark and Ninja brands consistently launch successful new products — a growth-oriented consumer brand with strong retail shelf presence and loyal customer following.", ["Shark vacuums and Ninja kitchen appliances — consistent product innovation and launch.", "ROIC of 25.1% reflects strong brand economics and successful product expansion.", "EPS grew 16.1% annualised with consistent innovation and category expansion.", "Revenue grew 15.7% annualised as new product categories and international expansion drove growth."]),
    650: ('Talkspace Inc', 'US online therapy platform. Exceptional ROIC.', 'Online therapy platform.', "Talkspace is a US online mental health platform providing therapy through text, audio, and video sessions with licensed therapists. The company serves individuals, employers, and health plans — a growing market as mental health awareness and telehealth adoption increase.", 'Online therapy. Exceptional ROIC.', 'Mental health platform compounder.', "A US online therapy platform with a 67.5% ROIC and EPS growth of 22.7% annualised. Talkspace provides accessible mental health services through digital channels — exceptional capital efficiency from a scalable telehealth model serving a massive and growing mental health demand.", ["Online therapy platform providing text, audio and video sessions with licensed therapists.", "ROIC of 67.5% — exceptional returns from a scalable online mental health model.", "EPS grew 22.7% annualised as mental health platform adoption and revenue expanded.", "Revenue grew 11.3% annualised with consistent employer and health plan contract additions."]),
    651: ('TAT Technologies Ltd', 'Israeli aerospace heat management. High growth.', 'Aerospace thermal management.', "TAT Technologies is an Israeli manufacturer of heat exchangers and thermal management systems for aerospace and defence applications. The company produces oil coolers, fuel heaters, and environmental control systems for military and commercial aircraft.", 'Aerospace heat management. High growth.', 'Aerospace thermal compounder.', "An Israeli aerospace thermal management company with an 11.9% ROIC and EPS growth of 41.0% annualised. TAT Technologies produces heat exchangers and thermal systems for military and commercial aircraft — growing strongly as aerospace production recovers.", ["Heat exchangers and thermal management systems for military and commercial aircraft.", "ROIC of 11.9% reflects consistent returns from aerospace thermal management expertise.", "EPS grew 41.0% annualised as aerospace production recovery drove thermal component demand.", "Revenue grew 17.0% annualised with consistent aerospace and defence programme wins."]),
    652: ('TG Therapeutics Inc', 'US oncology and autoimmune drugs. Exceptional ROIC.', 'Oncology pharmaceutical growth.', "TG Therapeutics is a US pharmaceutical company with Briumvi — an anti-CD20 monoclonal antibody for relapsing multiple sclerosis. The drug competes in a large and growing MS market with a differentiated infusion profile.", 'Multiple sclerosis drug. Exceptional ROIC.', 'Neuro pharma compounder.', "A US pharmaceutical company with a 58.3% ROIC and revenue growth of 87.3% annualised from Briumvi — an anti-CD20 therapy for relapsing multiple sclerosis. TG Therapeutics competing in the large MS market with a commercially established drug showing strong prescription growth.", ["Briumvi anti-CD20 therapy for relapsing multiple sclerosis — large and growing MS market.", "ROIC of 58.3% — exceptional returns from a commercially established neurological drug.", "EPS grew 26.8% annualised as Briumvi prescriptions expanded from market launch.", "Revenue grew 87.3% annualised as Briumvi gained market share in the MS treatment market."]),
    653: ('The Scotts Miracle Gro Co', 'US lawn and garden products. Growth recovery.', 'Lawn and garden recovery.', "Scotts Miracle-Gro is the world's leading supplier of branded lawn and garden products — Scotts fertilisers, Miracle-Gro plant food, and Ortho pest control. The company is recovering from a difficult period following pandemic-era demand normalisation.", 'Lawn and garden. Growth recovery.', 'Garden products recovery compounder.', "A US lawn and garden company with a 4.3% ROIC recovering from pandemic demand normalisation. Scotts Miracle-Gro owns the dominant US lawn and garden brands — structural recovery as consumer gardening demand stabilises and inventory levels normalise.", ["Scotts, Miracle-Gro and Ortho — dominant US lawn and garden product brands.", "Recovery play as pandemic-era demand normalisation completes and inventories clear.", "Structural long-term demand from growing US homeowner gardening and lawn care.", "Revenue recovering as retail inventory levels and consumer demand patterns normalise."]),
    654: ('Theravance Biopharma Inc', 'US respiratory rare disease pharma. Exceptional ROIC.', 'Respiratory rare disease drug.', "Theravance Biopharma receives royalties from GSK on Trelegy Ellipta — a leading respiratory triple therapy for COPD and asthma. The company is transitioning to a royalty model with minimal operating costs and high cash conversion.", 'GSK respiratory royalties. Exceptional ROIC.', 'Respiratory royalty compounder.', "A US respiratory pharmaceutical royalty company with an 80.3% ROIC receiving royalties on GSK Trelegy Ellipta — a leading COPD and asthma triple therapy. Theravance transitioning to a pure royalty model — exceptional returns with minimal operating costs.", ["GSK Trelegy Ellipta respiratory royalties — leading COPD and asthma triple therapy.", "ROIC of 80.3% — exceptional returns from respiratory drug royalty income.", "Revenue grew 66.9% annualised as Trelegy Ellipta prescriptions expanded strongly.", "Transitioning to pure royalty model with minimal operating costs and high cash conversion."]),
    655: ('Tonies SE', 'German children audio platform. High growth.', 'Children audio content growth.', "Tonies makes Toniebox — a screen-free audio player for young children using physical character figurines to play stories, music, and educational content. The company has built a strong brand in German-speaking markets and is expanding internationally.", 'Children audio player. High growth.', 'Kids content platform compounder.', "A German children audio platform with an 8.2% ROIC and EPS growth of 20.6% annualised. Tonies Toniebox is a beloved screen-free audio system for children — growing international expansion beyond core German market into US and UK.", ["Toniebox screen-free audio player for children — stories, music and educational content.", "ROIC of 8.2% with improving trajectory as international expansion scales.", "EPS grew 20.6% annualised as Tonies household penetration and Tonie sales expanded.", "Revenue grew 29.3% annualised with consistent international market entry and expansion."]),
    656: ('Trophy Games', 'Danish board game publisher. High growth.', 'Board game growth publisher.', "Trophy Games is a Danish publisher of board games and tabletop games targeting families and hobby gamers. The company benefits from structural growth in the tabletop gaming market as families seek screen-free entertainment alternatives.", 'Board games. High growth momentum.', 'Tabletop gaming compounder.', "A Danish board game publisher with EPS growth of 28.2% annualised. Trophy Games produces tabletop games for families and hobby gamers — benefiting from structural growth in the tabletop gaming market and growing hobby gaming communities.", ["Board games and tabletop games for families and hobby gamers globally.", "EPS grew 28.2% annualised as tabletop gaming demand and game catalogue expanded.", "Revenue grew 40.4% annualised as board game market growth and new titles drove sales.", "Structural growth in tabletop gaming as families seek screen-free entertainment."]),
    657: ('Twin Disc Inc', 'US power transmission equipment. Growth recovery.', 'Power transmission recovery.', "Twin Disc manufactures power transmission equipment — torque converters, transmissions, and clutches for industrial, marine, and agricultural applications. The company is recovering with improving financial metrics as industrial demand and agricultural equipment sales normalise.", 'Power transmission. Growth recovery.', 'Industrial transmission recovery.', "A US power transmission equipment manufacturer with an 8.7% ROIC showing growth recovery. Twin Disc produces torque converters and clutches for industrial, marine, and agricultural applications — improving earnings as equipment demand recovers across end markets.", ["Torque converters, transmissions and clutches for industrial, marine and agricultural use.", "ROIC of 8.7% recovering as industrial and agricultural equipment demand normalises.", "EPS grew 21.9% annualised as power transmission demand and margins improved.", "Revenue grew 8.3% annualised with consistent demand from industrial and agricultural markets."]),
    659: ('Valeura Energy Inc', 'Canadian oil producer in Thailand. Growth momentum.', 'Thailand offshore oil growth.', "Valeura Energy is a Canadian oil producer operating offshore concessions in the Gulf of Thailand. The company acquired producing Gulf of Thailand assets and has grown production and free cash flow significantly since acquisition.", 'Thailand offshore oil. Growth momentum.', 'Emerging market oil growth compounder.', "A Canadian oil producer in the Gulf of Thailand with a 5.4% ROIC and EPS growth of 23.8% annualised. Valeura acquired Gulf of Thailand concessions and has rapidly grown production — generating strong free cash flow from low-cost offshore oil operations.", ["Offshore oil production from concessions in the Gulf of Thailand.", "ROIC of 5.4% with improving trajectory as production growth drives cash flow higher.", "EPS grew 23.8% annualised as production from Gulf of Thailand fields expanded.", "Strong free cash flow generation from low-cost Gulf of Thailand offshore production."]),
    660: ('Veracyte Inc', 'US genomic cancer diagnostics. High ROIC.', 'Genomic diagnostics growth.', "Veracyte is a US genomic diagnostics company providing RNA-based cancer tests that help physicians make better treatment decisions for thyroid, lung, and other cancers. The company Afirma test is the standard of care for thyroid nodule evaluation.", 'Genomic cancer diagnostics. High ROIC.', 'Cancer diagnostics compounder.', "A US genomic cancer diagnostics company with a 7.1% ROIC and EPS growth of 26.8% annualised. Veracyte Afirma thyroid test is the standard of care for thyroid nodule evaluation — a clinically validated diagnostic that avoids unnecessary surgery in thousands of patients annually.", ["RNA-based genomic tests for thyroid, lung and other cancers — standard of care.", "ROIC of 7.1% with improving trajectory as test volumes and reimbursement expand.", "EPS grew 26.8% annualised as genomic test adoption and clinical validation broadened.", "Revenue grew 16.0% annualised with consistent test volume growth from physician adoption."]),
    661: ('Western Digital Corp', 'US data storage technology. AI tailwind.', 'Data storage AI beneficiary.', "Western Digital produces hard disk drives and NAND flash memory for cloud, enterprise, and consumer markets. The company is a direct beneficiary of the AI infrastructure buildout — unprecedented data centre storage demand is driving exceptional earnings recovery.", 'Data storage. AI infrastructure tailwind.', 'Storage technology AI compounder.', "A US data storage company with a 59.5% ROIC recovering strongly as AI infrastructure drives unprecedented cloud storage demand. Western Digital produces HDDs and NAND flash for hyperscale data centres — exceptional growth from the AI data storage buildout.", ["Hard disk drives and NAND flash memory for cloud, enterprise and consumer storage.", "ROIC of 59.5% reflects strong recovery as AI data centre storage demand surged.", "EPS grew 33.6% annualised as AI infrastructure buildout drove unprecedented storage demand.", "Revenue grew 28.1% annualised as hyperscale cloud storage investment accelerated."]),
    662: ('Whats Cooking Group NVSA', 'Belgian food manufacturing. Exceptional revenue growth.', 'Belgian food manufacturing growth.', "Whats Cooking Group is a Belgian food manufacturing company producing ready meals, sauces, and convenience foods for retail and foodservice customers across Europe. The company benefits from growing demand for convenient, quality food products.", 'Belgian food manufacturing. Exceptional growth.', 'European food manufacturing compounder.', "A Belgian food manufacturing company with a 23.6% ROIC and exceptional revenue growth of 119.4% annualised. Whats Cooking Group produces ready meals and convenience foods for European retail and foodservice — strong growth from acquisitions and organic market expansion.", ["Ready meals, sauces and convenience foods for European retail and foodservice.", "ROIC of 23.6% reflects strong returns from efficient food manufacturing operations.", "EPS grew 49.2% annualised as acquisitions and organic growth expanded the business.", "Revenue grew 119.4% annualised driven by acquisitions and European market expansion."]),
}
with open(CARDS_PATH, "r", encoding="utf-8") as f:
    content = f.read()
updated = 0
for card_id, (company, tag, tagBold, tagFull, pick, pickBold, pickFull, bullets) in descriptions.items():
    pattern = re.compile(rf"(id: {card_id}, type: .JOKER..*?tag: ')[^']*('..*?tagBold: ')[^']*('..*?tagFull: \")[^\"]*(\",.*?pick: ')[^']*('..*?pickBold: ')[^']*('..*?pickFull: \")[^\"]*(\",)", re.DOTALL)
    replacement = rf"\g<1>{tag}\g<2>{tagBold}\g<3>{tagFull}\g<4>{pick}\g<5>{pickBold}\g<6>{pickFull}\g<7>"
    new_content = pattern.sub(replacement, content)
    if new_content != content:
        content = new_content
        updated += 1
        print(f"OK {card_id}: {company}")
    else:
        print(f"MISS {card_id}: {company}")
    bullets_str = ", ".join([f'"{b}"' for b in bullets])
    bp = re.compile(rf"(id: {card_id},.*?bullets: \[)[^\]]*\]", re.DOTALL)
    content = bp.sub(rf"\g<1>{bullets_str}]", content)
with open(CARDS_PATH, "w", encoding="utf-8") as f:
    f.write(content)
print(f"Updated: {updated}")
print(f"Remaining: {content.count('operates in')}")
